A simple (Stupid) example:

```julia
using Convex;
using ECOS;

numSamples = 100;
vY = rand(numSamples);

valThr = sort(vY)[5];
vP = vY .>= valThr; #<! Set of boolean indices

vX = Variable(numSamples);
sConvProb = minimize( 0.5 * sumsquares(vX - vY), [vX[vP] == vY[vP]] ); #<! Will fail
solve!(sConvProb, ECOS.Optimizer; silent = true);
